# Write a Firmware Module

Modules extend a CONDUYT device with custom hardware capabilities. Each module handles commands from the host, can emit events, and runs a poll loop for background work.

Write a custom module when built-in pin control and datastreams aren't enough - for example, devices with initialization sequences (displays), multi-step protocols (1-Wire sensors), or continuous processing (PID loops, stepper pulse generation).

## The module interface

Every module implements `ConduytModuleBase`:

```cpp
class ConduytModuleBase {
public:
  virtual const char* name() = 0;        // module name, max 8 characters
  virtual uint8_t versionMajor() { return 1; }
  virtual uint8_t versionMinor() { return 0; }
  virtual void begin() {}                // called after device.begin()
  virtual void handle(uint8_t cmd, ConduytPayloadReader &payload, ConduytContext &ctx) = 0;
  virtual void poll() {}                 // called every device.poll() cycle
  virtual uint8_t pinCount() { return 0; }
  virtual const uint8_t* pins() { return nullptr; }
};
```

## Example: a relay module

This module controls a relay on pin 4 with two commands: set state and read state.

```cpp
#define CONDUYT_MODULE_RELAY
#include <Conduyt.h>

CONDUYT_MODULE(RelayModule) {
public:
  const char* name() override { return "relay"; }
  uint8_t versionMajor() override { return 1; }
  uint8_t versionMinor() override { return 0; }

  void begin() override {
    // Called once after device.begin() - initialize your hardware here
    pinMode(_pin, OUTPUT);
    digitalWrite(_pin, LOW);
  }

  void handle(uint8_t cmd, ConduytPayloadReader &payload, ConduytContext &ctx) override {
    CONDUYT_ON_CMD(0x01) {
      // Command 0x01: Set relay state
      // Host sends: [0 or 1]
      uint8_t state = payload.readUInt8();
      digitalWrite(_pin, state ? HIGH : LOW);
      ctx.ack();   // confirm the command succeeded
    }

    CONDUYT_ON_CMD(0x02) {
      // Command 0x02: Read relay state
      // Host sends: nothing
      // We respond with: [0 or 1]
      uint8_t buf[1];
      ConduytPayloadWriter w(buf, sizeof(buf));
      w.writeUInt8(digitalRead(_pin));
      ctx.sendModResp(0x02, buf, w.length());
    }
  }

  void poll() override {
    // Called every loop cycle - nothing to do for a relay
  }

private:
  uint8_t _pin = 4;
};
```

## Register the module

Add modules before calling `device.begin()`. Module IDs are assigned by registration order - first module = ID 0, second = ID 1, etc.

```cpp
void setup() {
  Serial.begin(115200);

  device.addModule(new RelayModule());        // module ID 0
  device.addModule(new TempSensorModule());   // module ID 1
  device.begin();
}
```

These IDs appear in the HELLO_RESP packet so the host knows what modules are available and how to address them.

## Context API reference

The `ConduytContext` passed to `handle()` controls how the device responds:

| Method | When to use | What it sends |
|--------|------------|---------------|
| `ctx.ack()` | Command succeeded, no data to return | ACK packet |
| `ctx.nak(errorCode)` | Command failed | NAK packet with error code |
| `ctx.sendModResp(cmdId, data, len)` | Command succeeded, returning data | MOD_RESP packet |
| `ctx.emitModEvent(eventId, code, data, len)` | Unsolicited event from module | MOD_EVENT packet |

If your handler doesn't call any of these, `ConduytDevice` auto-sends an ACK.

## Reading command payloads

`ConduytPayloadReader` reads typed values in order from the command payload. All multi-byte values are **little-endian**.

```cpp
void handle(uint8_t cmd, ConduytPayloadReader &payload, ConduytContext &ctx) override {
  CONDUYT_ON_CMD(0x01) {
    uint8_t  pin   = payload.readUInt8();     // 1 byte
    uint16_t speed = payload.readUInt16();    // 2 bytes, little-endian
    float    angle = payload.readFloat32();   // 4 bytes, IEEE 754
    ctx.ack();
  }
}
```

## Writing response payloads

`ConduytPayloadWriter` builds response data into a buffer:

```cpp
CONDUYT_ON_CMD(0x02) {
  uint8_t buf[8];
  ConduytPayloadWriter w(buf, sizeof(buf));
  w.writeUInt8(0x01);          // status byte
  w.writeFloat32(23.5f);       // temperature
  w.writeUInt16(512);          // raw ADC value
  ctx.sendModResp(0x02, buf, w.length());  // w.length() = 7 bytes
}
```

## Poll loop

`poll()` runs every `device.poll()` cycle. Use it for continuous background work. Keep it **fast and non-blocking** - never call `delay()` inside `poll()`.

```cpp
void poll() override {
  unsigned long now = millis();
  if (now - _lastRead >= 1000) {
    _lastRead = now;
    _latestTemp = readSensor();
    _hasNewReading = true;
  }
}
```

`poll()` doesn't receive a `ConduytContext`, so it can't send responses directly. Store results in member variables and return them when the host sends a read command via `handle()`.

## Control the module from the host

### JavaScript

The JavaScript SDK has a `.module()` proxy that sends MOD_CMD packets by name:

```javascript
// Get the module proxy - 'relay' matches the name() return value in firmware
const relay = device.module('relay')

// Send command 0x01 (set state) with payload [1] (on)
await relay.cmd(0x01, new Uint8Array([1]))
console.log('Relay ON')

// Send command 0x02 (read state), receive response bytes
const resp = await relay.cmd(0x02)
console.log('Relay state:', resp[0])   // 0 or 1
```

### Python

The Python SDK doesn't have a `.module()` proxy. For custom modules, write a thin wrapper:

```python
# relay.py
from conduyt.protocol import CMD_MOD_CMD


class RelayModule:
    """Host-side wrapper for the relay firmware module."""

    def __init__(self, device, module_id: int):
        self._device = device
        self._id = module_id

    async def set_state(self, on: bool):
        """Send command 0x01: set relay state."""
        payload = bytes([self._id, 0x01, int(on)])
        await self._device._send_command(CMD_MOD_CMD, payload)

    async def get_state(self) -> int:
        """Send command 0x02: read relay state."""
        payload = bytes([self._id, 0x02])
        resp = await self._device._send_command(CMD_MOD_CMD, payload)
        return resp[0]
```

Usage:

```python
relay = RelayModule(device, module_id=0)

await relay.set_state(True)
print("Relay ON")

state = await relay.get_state()
print(f"Relay state: {state}")  # 0 or 1
```

The built-in module wrappers in `conduyt.modules` (Servo, NeoPixel, DHT, etc.) use the same `_send_command()` pattern internally.

## Compile guards

Gate each module with a `#define` to keep binary size small on constrained boards (Uno R3 has only 32 KB flash):

```cpp
#define CONDUYT_MODULE_RELAY
#define CONDUYT_MODULE_TEMPSENSOR
#include <Conduyt.h>
```

Only the modules you define get compiled. This is especially important on AVR boards where every kilobyte counts.

# Update Firmware Over the Air

Once a device is running CONDUYT firmware compiled with `-DCONDUYT_OTA`, the host can replace its firmware over whatever transport is already connected (Serial, BLE, MQTT bridge, WebSerial in the browser). No USB cable, no DFU button, no `esp-web-tools`.

The flow is simple:

1. The host computes a SHA-256 of the new firmware blob.
2. It sends `OTA_BEGIN` with the total byte count + the SHA-256.
3. It streams the firmware in `OTA_CHUNK` packets at sequential offsets.
4. It sends `OTA_FINALIZE` to verify the digest and reboot into the new image.

Every SDK ships a typed `ConduytOTA` orchestrator that does all four steps for you.

## Firmware setup

OTA support is opt-in per board. Add the compile flag and let CONDUYT's `ConduytOTA` runtime hook into the device:

```ini
; platformio.ini
[env:esp32dev]
platform = espressif32
board = esp32dev
framework = arduino
build_flags = -DCONDUYT_OTA
```

```cpp
#include <Conduyt.h>

ConduytSerial transport(Serial, 115200);
ConduytDevice device("MyBoard", "1.0.0", transport);

void setup() {
  Serial.begin(115200);
  device.begin();   // OTA handlers wire in automatically when CONDUYT_OTA is defined
}

void loop() {
  device.poll();
}
```

OTA today is supported on the **ESP32 family** (esp32, S2, S3, C3) and **Arduino Nano ESP32** . wherever `Update.h` is available. AVR boards (Uno R3, Nano, Mega) and most Cortex-M boards (Teensy, Pico, R4 Minima) lack the bootloader / off-chip flash needed for in-place updates and currently NAK `OTA_BEGIN` with `OTA_INVALID` (0x0F). Check `device.capabilities.otaCapable` before starting.

## Host usage

Identical wire bytes, identical chunk size auto-tuning, identical progress callback, in every SDK:

### JavaScript

```javascript
import { ConduytDevice, ConduytOTA } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'

const device = await ConduytDevice.connect(new SerialTransport({ path: '<YOUR_PORT>' }))
if (!device.capabilities?.otaCapable) {
  throw new Error('Firmware does not support OTA . rebuild with -DCONDUYT_OTA')
}

const fw = new Uint8Array(await fs.promises.readFile('./firmware.bin'))
const ota = new ConduytOTA(device)

await ota.flash(fw, {
  onProgress: (sent, total) => console.log(`${sent}/${total} (${(100 * sent / total).toFixed(1)}%)`),
})

console.log('Flashed . device is rebooting.')
```

### Python

```python
import asyncio
from conduyt import ConduytDevice, ConduytOTA
from conduyt.transports.serial import SerialTransport


async def main():
    device = ConduytDevice(SerialTransport('<YOUR_PORT>'))
    await device.connect()
    if not device.capabilities.ota_capable:
        raise RuntimeError("Firmware does not support OTA . rebuild with -DCONDUYT_OTA")

    with open('firmware.bin', 'rb') as f:
        fw = f.read()

    ota = ConduytOTA(device)
    await ota.flash(
        fw,
        on_progress=lambda sent, total: print(f"{sent}/{total} ({100*sent/total:.1f}%)"),
    )


asyncio.run(main())
```

### Go

```go
package main

import (
    "context"
    "fmt"
    "log"
    "os"

    conduyt "github.com/virgilvox/conduyt/sdk/go"
    "github.com/virgilvox/conduyt/sdk/go/ota"
    "github.com/virgilvox/conduyt/sdk/go/transports"
)

func main() {
    transport, _ := transports.NewSerial("/dev/cu.usbmodem14101", 115200)
    device := conduyt.NewDevice(transport, 5_000_000_000)
    ctx := context.Background()
    if _, err := device.Connect(ctx); err != nil { log.Fatal(err) }

    fw, err := os.ReadFile("firmware.bin")
    if err != nil { log.Fatal(err) }

    err = ota.Flash(ctx, device, fw, ota.Options{
        OnProgress: func(sent, total int) {
            fmt.Printf("%d / %d (%.1f%%)\n", sent, total, 100.0*float64(sent)/float64(total))
        },
    })
    if err != nil { log.Fatal(err) }
}
```

### Rust

```toml
# Cargo.toml
[dependencies]
conduyt = { version = "0.3", features = ["ota"] }
```

```rust
use conduyt::device::Device;
use conduyt::ota::{flash, FlashOptions};
use conduyt::transports::serial::SerialTransport;

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let transport = SerialTransport::open("/dev/cu.usbmodem14101", 115200)?;
    let mut device = Device::new(transport);
    device.connect()?;

    let fw = std::fs::read("firmware.bin")?;
    let mut on_progress = |sent: usize, total: usize| {
        println!("{} / {} ({:.1}%)", sent, total, 100.0 * sent as f64 / total as f64);
    };
    flash(&mut device, &fw, FlashOptions {
        on_progress: Some(&mut on_progress),
        ..Default::default()
    })?;
    Ok(())
}
```

### Swift

```swift
import ConduytKit
import Foundation

let transport = BLETransport(serviceUUID: ...)
let device = ConduytDevice(transport: transport)
_ = try await device.connect()

let fwURL = Bundle.main.url(forResource: "firmware", withExtension: "bin")!
let fw = try Data(contentsOf: fwURL)

let ota = ConduytOTA(device: device)
try await ota.flash(fw, options: OTAFlashOptions(onProgress: { sent, total in
    print("\(sent) / \(total) (\(100 * Double(sent) / Double(total))%)")
}))
```

## Wire format reference

| Command | ID | Payload | NAK code on error |
|---|---|---|---|
| OTA_BEGIN | `0x70` | `total_bytes (u32 LE) + sha256 (32 bytes)` | `0x0F OTA_INVALID` |
| OTA_CHUNK | `0x71` | `offset (u32 LE) + data (N bytes)` | `0x0F OTA_INVALID` (out-of-order or after Update.write fails) |
| OTA_FINALIZE | `0x72` | (empty) | `0x0F OTA_INVALID` (digest mismatch / Update.end failure) |

After `OTA_FINALIZE` ACKs, the firmware reboots immediately. Any packet sent on the same connection in the next ~1-3 seconds will fail. Reconnect.

## Notes

- **Chunk size**: each SDK auto-sizes chunks based on `HELLO_RESP.maxPayload`. The device reserves 4 bytes of every payload for the offset header, so chunks are `(maxPayload - 4)` bytes by default. ESP32 advertises 1024, so chunks are 1020 bytes . about 2 chunks per kilobyte of firmware.
- **Sequential offsets**: chunks must be sent in ascending offset order. The firmware NAKs any out-of-order chunk to keep `Update.write` happy. None of the SDK orchestrators reorder, so this is automatic if you use them.
- **Hashing on the host**: the SHA-256 is computed on the host and verified by the firmware at finalize time. A mid-flight transport corruption that slips past CRC8 will still get caught here.
- **Rollback**: there's no rollback in the OTA spec itself . if the new firmware bricks itself, you fall back to USB / DFU. Keep a known-good build handy.

# Use Datastreams

Datastreams are named, typed data channels between a device and host. Use them for structured application data: sensor readings with units, configuration values, status indicators. For direct hardware control (toggling pins, reading raw ADC), use the [pin API](/docs/reference/js-api) instead.

## 1. Declare datastreams on the device

Register datastreams before calling `device.begin()`:

```cpp
#include <Conduyt.h>

ConduytSerial transport(Serial, 115200);
ConduytDevice device("TempNode", "1.0.0", transport);

void setup() {
  Serial.begin(115200);

  // Read-only: device pushes values, host reads/subscribes
  // Args: name, type, unit, writable
  device.addDatastream("temperature", CONDUYT_FLOAT32, "celsius", false);

  // Writable: host writes values, device receives them
  device.addDatastream("setpoint", CONDUYT_FLOAT32, "celsius", true);

  device.begin();
}
```

The fourth argument controls direction:
- `false` = **read-only** - device pushes, host reads
- `true` = **writable** - host writes, device receives

## 2. Push values from the device

Use non-blocking timing to push values at a fixed interval:

```cpp
unsigned long lastPush = 0;

void loop() {
  device.poll();

  // Push temperature every 1 second
  if (millis() - lastPush >= 1000) {
    lastPush = millis();

    float temp = analogRead(A0) * 0.48828125f;  // rough voltage-to-celsius
    device.writeDatastream("temperature", temp);
  }
}
```

Each `writeDatastream()` call sends a DS_EVENT packet to the host. Don't call it every loop iteration - the serial link can't keep up with tens of thousands of updates per second.

## 3. Receive writes on the device

Register a callback for writable datastreams:

```cpp
device.onDatastreamWrite("setpoint", [](ConduytPayloadReader &payload, ConduytContext &ctx) {
  float value = payload.readFloat32();
  Serial.print("New setpoint: ");
  Serial.println(value);
  // Apply the value to your control logic here
  ctx.ack();  // confirm receipt
});
```

If you don't call `ctx.ack()`, the device auto-acks. Call `ctx.nak(errorCode)` to reject a write.

## Available type codes

| Code | Constant | Size | Range |
|------|----------|------|-------|
| `0x01` | `CONDUYT_BOOL` | 1 byte | 0 or 1 |
| `0x02` | `CONDUYT_INT8` | 1 byte | -128 to 127 |
| `0x03` | `CONDUYT_UINT8` | 1 byte | 0 to 255 |
| `0x04` | `CONDUYT_INT16` | 2 bytes | -32768 to 32767 |
| `0x05` | `CONDUYT_UINT16` | 2 bytes | 0 to 65535 |
| `0x06` | `CONDUYT_INT32` | 4 bytes | -2^31 to 2^31-1 |
| `0x07` | `CONDUYT_FLOAT32` | 4 bytes | IEEE 754 float |
| `0x08` | `CONDUYT_STRING` | variable | UTF-8, null-terminated |
| `0x09` | `CONDUYT_BYTES` | variable | Raw binary |

The verbose `CONDUYT_TYPE_<NAME>` forms in `Conduyt.h` are aliases of these short forms; either works in `addDatastream()`.

## Host: JavaScript

### Read the current value

```javascript
const temp = await device.datastream('temperature').read()
console.log('Temperature:', temp)
```

### Write a value

```javascript
await device.datastream('setpoint').write(25.0)
```

### Subscribe to live updates

```javascript
// Yields a new value each time the device pushes an update
for await (const value of device.datastream('temperature').subscribe()) {
  console.log('Temperature:', value)
}
```

### Full working example

```javascript
// datastreams.mjs
import { ConduytDevice } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'

const device = await ConduytDevice.connect(
  new SerialTransport({ path: '<YOUR_PORT>', baudRate: 115200 })
)

// Read current temperature
const temp = await device.datastream('temperature').read()
console.log('Current temp:', temp)

// Set target temperature
await device.datastream('setpoint').write(22.0)
console.log('Setpoint set to 22.0')

// Stream live updates (runs until you Ctrl+C)
console.log('Streaming temperature updates...')
for await (const value of device.datastream('temperature').subscribe()) {
  console.log('Temperature:', value)
}
```

```bash
node datastreams.mjs
```

## Host: Python

```python
# datastreams.py
import asyncio
from conduyt import ConduytDevice
from conduyt.transports.serial import SerialTransport
from conduyt.protocol import CMD_DS_READ, CMD_DS_WRITE, CMD_DS_SUBSCRIBE
import struct


async def main():
    device = ConduytDevice(SerialTransport('<YOUR_PORT>'))
    await device.connect()

    # Read current temperature
    # Send DS_READ command with the datastream name
    resp = await device._send_command(
        CMD_DS_READ,
        b'temperature\x00'  # null-terminated datastream name
    )
    temp = struct.unpack('<f', resp[:4])[0]
    print(f"Current temp: {temp:.1f}")

    # Write setpoint
    # Send DS_WRITE with name + float32 value
    payload = b'setpoint\x00' + struct.pack('<f', 22.0)
    await device._send_command(CMD_DS_WRITE, payload)
    print("Setpoint set to 22.0")

    await device.disconnect()


asyncio.run(main())
```

**Note:** The Python SDK doesn't have a `.datastream()` proxy like JavaScript. You send raw DS_READ/DS_WRITE/DS_SUBSCRIBE commands using `_send_command()`. The built-in module wrappers in `conduyt.modules` use the same pattern internally.

## Full firmware example

```cpp
#include <Conduyt.h>

ConduytSerial transport(Serial, 115200);
ConduytDevice device("TempNode", "1.0.0", transport);

float currentSetpoint = 20.0f;

void setup() {
  Serial.begin(115200);

  device.addDatastream("temperature", CONDUYT_FLOAT32, "celsius", false);
  device.addDatastream("setpoint", CONDUYT_FLOAT32, "celsius", true);

  device.onDatastreamWrite("setpoint", [](ConduytPayloadReader &payload, ConduytContext &ctx) {
    currentSetpoint = payload.readFloat32();
    Serial.print("New setpoint: ");
    Serial.println(currentSetpoint);
    ctx.ack();
  });

  device.begin();
}

unsigned long lastPush = 0;

void loop() {
  device.poll();

  if (millis() - lastPush >= 1000) {
    lastPush = millis();
    float temp = analogRead(A0) * 0.48828125f;
    device.writeDatastream("temperature", temp);
  }
}
```

For wire format details and type encoding, see [Datastream Types](/docs/reference/datastream-types).
